import{_ as a,o as d,c as n,a2 as s}from"./chunks/framework.BnBoz4Zl.js";const e="/anjian-workbuddy-bluebook-site/assets/001_image_MuLCbdPyDo.CC7t9EuE.png",r="/anjian-workbuddy-bluebook-site/assets/002_image_DtASbQcrto.D8OmFDwj.png",l="/anjian-workbuddy-bluebook-site/assets/003_image_W7VqbwVeJo.1GRpiN8R.png",o="/anjian-workbuddy-bluebook-site/assets/004_image_JiigbkdTKo.DjMprcaA.png",_=JSON.parse('{"title":"第 3 章 WorkBuddy 的主界面、任务与工作区","description":"WorkBuddy 主界面可以理解为三个区域：左侧（侧边栏）管理任务，中间（对话区）下达和追踪任务，右侧（结果区）查看文件、变更、预览和最终产物。 工作目录既是效率设置，也是安全边界。把发票、周报、客户材料混在同一个大目录里，会增加误读、误改和信息串用的风险。","frontmatter":{},"headers":[],"relativePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 3 章 WorkBuddy 的主界面、任务与工作区/index.md","filePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 3 章 WorkBuddy 的主界面、任务与工作区/index.md","lastUpdated":1784289416000}'),i={name:"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 3 章 WorkBuddy 的主界面、任务与工作区/index.md"};function p(h,t,b,c,u,g){return d(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="第-3-章-workbuddy-的主界面、任务与工作区" tabindex="-1">第 3 章 WorkBuddy 的主界面、任务与工作区 <a class="header-anchor" href="#第-3-章-workbuddy-的主界面、任务与工作区" aria-label="Permalink to &quot;第 3 章 WorkBuddy 的主界面、任务与工作区&quot;">​</a></h1><p>WorkBuddy 主界面可以理解为三个区域：左侧（侧边栏）管理任务，中间（对话区）下达和追踪任务，右侧（结果区）查看文件、变更、预览和最终产物。</p><p><img src="'+e+'" alt="" loading="lazy"></p><h2 id="三个区域分别做什么" tabindex="-1">三个区域分别做什么 <a class="header-anchor" href="#三个区域分别做什么" aria-label="Permalink to &quot;三个区域分别做什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>区域</th><th>主要用途</th><th>使用时重点检查</th></tr></thead><tbody><tr><td>侧边栏</td><td>新建、搜索、切换和管理任务</td><td>是否进入了正确任务</td></tr><tr><td>对话区</td><td>描述需求、补充信息、确认计划</td><td>目标和约束是否完整</td></tr><tr><td>结果区</td><td>查看产物、全部文件、变更与预览</td><td>文件名、路径和改动是否符合预期</td></tr></tbody></table><h2 id="为什么要隔离工作目录" tabindex="-1">为什么要隔离工作目录 <a class="header-anchor" href="#为什么要隔离工作目录" aria-label="Permalink to &quot;为什么要隔离工作目录&quot;">​</a></h2><p>工作目录既是效率设置，也是安全边界。把发票、周报、客户材料混在同一个大目录里，会增加误读、误改和信息串用的风险。</p><p>推荐按任务建目录空间。</p><p>同时，可以对目录空间的权限进行设置。开启“允许完全访问”后，Agent 可能读写授权目录之外的文件。只有任务确实需要并且范围已经确认时才短时开启，任务结束后及时恢复较低权限。</p><p><img src="'+r+'" alt="" loading="lazy"></p><h2 id="三种工作模式" tabindex="-1">三种工作模式 <a class="header-anchor" href="#三种工作模式" aria-label="Permalink to &quot;三种工作模式&quot;">​</a></h2><p>WorkBuddy 提供三种工作模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>中文界面</th><th>能做什么</th><th>适合场景</th></tr></thead><tbody><tr><td>Ask</td><td>问一问</td><td>问答、理解和查看，不修改文件</td><td>先了解资料、确认需求</td></tr><tr><td>Craft</td><td>做一做</td><td>可直接操作本地文件、运行代码及系统指令</td><td>路径清楚、风险较低的任务</td></tr><tr><td>Plan</td><td>想一想</td><td>先生成计划，确认后再执行</td><td>多步骤、跨系统、重要文件任务</td></tr></tbody></table><p><img src="'+l+`" alt="" loading="lazy"></p><h2 id="agent-高风险模式与高风险操作" tabindex="-1">Agent 高风险模式与高风险操作 <a class="header-anchor" href="#agent-高风险模式与高风险操作" aria-label="Permalink to &quot;Agent 高风险模式与高风险操作&quot;">​</a></h2><p>风险判断针对 Agent 获得的权限、准备执行的动作和资产当前状态。模型名称只能作为辅助信息，不能单独决定风险等级。</p><p>可以用下面的启发式快速判断损失半径：</p><blockquote><p>风险暴露 ≈ 权限范围 × 操作不可逆性 × 资产集中度</p></blockquote><p>这个表达只用于快速判断风险优先级，不用于计算事故概率。权限越广、动作越难撤销、重要资产越集中在唯一副本中，越需要降低权限、增加确认和准备恢复路径。</p><h3 id="哪些情况应按高风险处理" tabindex="-1">哪些情况应按高风险处理 <a class="header-anchor" href="#哪些情况应按高风险处理" aria-label="Permalink to &quot;哪些情况应按高风险处理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>风险来源</th><th>典型情况</th><th>主要后果</th></tr></thead><tbody><tr><td>权限范围过大</td><td>允许完全访问、跨工作区读取、连接器拥有写入权限</td><td>无关文件或系统被误读、误改</td></tr><tr><td>操作难以撤销</td><td>删除、覆盖、批量移动或重命名，执行系统命令，修改配置</td><td>原件、引用关系或运行环境受损</td></tr><tr><td>动作影响外部对象</td><td>发送邮件、发布内容、提交审批、更新业务记录</td><td>错误直接传递给客户、同事或正式系统</td></tr><tr><td>资产只有唯一副本</td><td>正式文件、关键数据或配置没有可恢复副本</td><td>一次误操作造成无法重建的损失</td></tr><tr><td>自动化扩大影响</td><td>定时执行、无人值守、批量循环、失败后自动重试</td><td>小错误快速扩散，难以及时停止</td></tr></tbody></table><h3 id="执行高风险任务前" tabindex="-1">执行高风险任务前 <a class="header-anchor" href="#执行高风险任务前" aria-label="Permalink to &quot;执行高风险任务前&quot;">​</a></h3><ol><li><strong>降低权限</strong>：优先使用 Ask 或 Plan；只授权本次任务所需目录、连接器和账号。</li><li><strong>只读预检</strong>：列出准确路径、对象数量、当前状态和计划动作，不立即写入。</li><li><strong>确认可恢复</strong>：重要资产先建立独立副本；需要恢复时，应已经知道从哪里恢复、由谁确认。</li><li><strong>生成变更预览</strong>：逐项列出原位置、拟操作、新位置、外部影响和冲突处理。</li><li><strong>等待明确确认</strong>：确认必须覆盖目标、范围、动作和影响，不能只问一句“是否继续”。</li><li><strong>先做小样本</strong>：在脱敏副本或少量对象上验证，再决定是否扩大范围。</li><li><strong>保留日志并检查结果</strong>：记录成功、跳过、冲突和失败，抽样打开产物并核对数量。</li><li><strong>收回临时权限</strong>：任务完成后关闭完全访问、写入连接和无人值守任务。</li></ol><h3 id="已经发生异常时怎样处置" tabindex="-1">已经发生异常时怎样处置 <a class="header-anchor" href="#已经发生异常时怎样处置" aria-label="Permalink to &quot;已经发生异常时怎样处置&quot;">​</a></h3><ol><li>立即停止当前 Agent、脚本和自动重试，防止影响继续扩大。</li><li>保留日志、时间、命令、目标路径和已产生的结果，不急于反复运行修复命令。</li><li>隔离受影响目录或系统，收回不必要的写入权限。</li><li>从最近一个可信快照恢复到新的空目录，先校验完整性，不覆盖仍在调查的现场。</li><li>由任务责任人核对恢复结果和业务影响，再决定是否替换正式目录、撤回外发内容或恢复自动化。</li></ol><h3 id="可复制高风险任务提示" tabindex="-1">可复制高风险任务提示 <a class="header-anchor" href="#可复制高风险任务提示" aria-label="Permalink to &quot;可复制高风险任务提示&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这是一项高风险任务。请先进入只读预检，不执行删除、覆盖、批量移动、外发或系统写入。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>任务目标：{目标}</span></span>
<span class="line"><span>授权范围：{目录、账号或系统}</span></span>
<span class="line"><span>禁止范围：{不能访问或修改的对象}</span></span>
<span class="line"><span>当前备份：{快照位置、时间和恢复责任人}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请先输出：</span></span>
<span class="line"><span>1. 准确目标和数量；</span></span>
<span class="line"><span>2. 权限范围及是否过大；</span></span>
<span class="line"><span>3. 拟执行动作、不可逆影响和失败停止条件；</span></span>
<span class="line"><span>4. 变更预览、冲突处理和回退路径；</span></span>
<span class="line"><span>5. 建议的小样本范围；</span></span>
<span class="line"><span>6. 需要我逐项确认的内容。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>没有明确确认，不执行写入。出现目标不明、路径异常、权限扩大或结果无法验收时立即停止。</span></span></code></pre></div><h2 id="选择不同的模型" tabindex="-1">选择不同的模型 <a class="header-anchor" href="#选择不同的模型" aria-label="Permalink to &quot;选择不同的模型&quot;">​</a></h2><p>默认为自动模式，可以指定你想使用的模型，不同模型积分消耗不同。</p><p><img src="`+o+'" alt="" loading="lazy"></p><p>模型名称和能力会随产品更新，不建议长期记住“某个模型只适合某类任务”。更稳妥的做法是按任务选择，并先用同一份脱敏小样本比较结果。</p><table tabindex="0"><thead><tr><th>任务特征</th><th>优先关注</th><th>建议验证</th></tr></thead><tbody><tr><td>大量文本与长资料</td><td>上下文长度、事实保持和中文结构能力</td><td>能否覆盖全部材料并准确引用</td></tr><tr><td>图片、截图或音视频</td><td>是否支持相应输入模态</td><td>能否识别关键内容和细节</td></tr><tr><td>表格、代码和文件处理</td><td>工具调用、格式生成和错误修复能力</td><td>产物能否打开、计算和复现</td></tr><tr><td>高频简单任务</td><td>响应速度和使用成本</td><td>质量达到要求后再批量使用</td></tr><tr><td>高风险专业任务</td><td>推理深度、证据意识和边界表达</td><td>只生成辅助材料，交专业人员复核</td></tr></tbody></table><p>最新模型通常能力更全面，但不代表每项任务都更合适。模型更新后应重新做小样本测试，并以 WorkBuddy 当前界面显示的能力和使用规则为准。</p>',33)])])}const m=a(i,[["render",p]]);export{_ as __pageData,m as default};
